package main

import (
	"database/sql"
	"fmt"
	"log"
	"os"

	_ "github.com/lib/pq"
)

// Config holds database connection parameters.
// For the demo, defaults are provided but should be overridden
// via environment variables or a .env file before any real use.
type Config struct {
	Host     string
	Port     string
	Database string
	User     string
	Password string
}

// getEnvOrDefault reads an environment variable or returns a fallback.
func getEnvOrDefault(key, fallback string) string {
	if value, exists := os.LookupEnv(key); exists {
		return value
	}
	return fallback
}

// LoadConfig loads database configuration from environment variables
// with demo defaults. Set these env vars before running:
//
//	export DB_HOST=localhost
//	export DB_PORT=5432
//	export DB_NAME=demo_db
//	export DB_USER=postgres
//	export DB_PASSWORD=<your-password>
func LoadConfig() Config {
	cfg := Config{
		Host:     getEnvOrDefault("DB_HOST", "localhost"),
		Port:     getEnvOrDefault("DB_PORT", "5432"),
		Database: getEnvOrDefault("DB_NAME", "demo_db"),
		User:     getEnvOrDefault("DB_USER", "postgres"),
		Password: os.Getenv("DB_PASSWORD"),
	}

	if cfg.Password == "" {
		log.Fatal("DB_PASSWORD environment variable is required. " +
			"Set it before running:\n  export DB_PASSWORD=<your-password>")
	}

	return cfg
}

// ConnectDB establishes a connection to the PostgreSQL database.
func ConnectDB() (*sql.DB, error) {
	cfg := LoadConfig()

	dsn := fmt.Sprintf(
		"host=%s port=%s user=%s password=%s dbname=%s sslmode=disable",
		cfg.Host, cfg.Port, cfg.User, cfg.Password, cfg.Database,
	)

	db, err := sql.Open("postgres", dsn)
	if err != nil {
		return nil, fmt.Errorf("failed to open database connection: %w", err)
	}

	if err := db.Ping(); err != nil {
		db.Close()
		return nil, fmt.Errorf("failed to ping database: %w", err)
	}

	log.Println("Successfully connected to the database")
	return db, nil
}

func main() {
	db, err := ConnectDB()
	if err != nil {
		log.Fatalf("Database connection failed: %v", err)
	}
	defer db.Close()

	log.Println("Demo application running...")
}